"""Register a one-shot plan: dispatch metadata and queued comment.

Composes independent operations that ``erk pr dispatch`` performs but
one-shot cannot do at submit time (the plan issue doesn't exist yet).
Each operation is best-effort; failures are logged but don't block others.
"""

import json
from datetime import UTC, datetime

import click

from erk.cli.commands.pr.metadata_helpers import write_dispatch_metadata
from erk_shared.context.helpers import (
    require_github,
    require_issues,
    require_plan_backend,
    require_repo_root,
)
from erk_shared.gateway.github.issues.types import IssueNotFound


@click.command(name="register-one-shot-plan")
@click.option("--plan-number", type=int, required=True)
@click.option("--run-id", type=str, required=True)
@click.option("--pr-number", type=int, required=True)
@click.option("--submitted-by", type=str, required=True)
@click.option("--run-url", type=str, required=True)
@click.pass_context
def register_one_shot_plan(
    ctx: click.Context,
    *,
    plan_number: int,
    run_id: str,
    pr_number: int,
    submitted_by: str,
    run_url: str,
) -> None:
    """Register a one-shot plan with issue metadata and comment."""
    issues = require_issues(ctx)
    github = require_github(ctx)
    plan_backend = require_plan_backend(ctx)
    repo_root = require_repo_root(ctx)
    results: dict[str, object] = {}

    # Op 1: dispatch metadata
    try:
        write_dispatch_metadata(
            plan_backend=plan_backend,
            github=github,
            repo_root=repo_root,
            plan_number=plan_number,
            run_id=run_id,
            dispatched_at=datetime.now(UTC).strftime("%Y-%m-%dT%H:%M:%SZ"),
        )
        results["dispatch_metadata"] = {"success": True}
    except Exception as exc:
        results["dispatch_metadata"] = {"success": False, "error": str(exc)}

    # Op 2: queued comment
    try:
        issue = issues.get_issue(repo_root, plan_number)
        if isinstance(issue, IssueNotFound):
            raise RuntimeError(f"Plan #{plan_number} not found")
        # Extract owner/repo from run_url for the PR link
        url_parts = run_url.split("/")
        repo_slug = next(
            (
                f"{url_parts[i + 1]}/{url_parts[i + 2]}"
                for i, p in enumerate(url_parts)
                if p == "github.com" and i + 2 < len(url_parts)
            ),
            "",
        )
        issues.add_comment(
            repo_root,
            plan_number,
            f"\U0001f504 **Queued for Implementation**\n\n"
            f"**Submitted by:** @{submitted_by}\n"
            f"**PR:** [#{pr_number}](https://github.com/{repo_slug}/pull/{pr_number})\n"
            f"**Workflow run:** [View run]({run_url})\n",
        )
        results["queued_comment"] = {"success": True}
    except Exception as exc:
        results["queued_comment"] = {"success": False, "error": str(exc)}

    # Op 3: update lifecycle stage to "planned"
    try:
        plan_backend.update_metadata(
            repo_root,
            str(plan_number),
            metadata={"lifecycle_stage": "planned"},
        )
        results["lifecycle_stage"] = {"success": True}
    except Exception as exc:
        results["lifecycle_stage"] = {"success": False, "error": str(exc)}

    click.echo(json.dumps(results, indent=2))
    if not any(v["success"] for v in results.values()):  # type: ignore[union-attr]
        raise SystemExit(1)

"""Fetch erk-plan issues linked to an objective.

Usage:
    erk exec get-plans-for-objective <OBJECTIVE_NUMBER>

Output:
    JSON with {success, objective_number, plans: [{number, state, title}]}

Exit Codes:
    0: Success - plans fetched
    1: Error - API error
"""

import json

import click

from erk_shared.context.helpers import (
    require_issues as require_github_issues,
)
from erk_shared.context.helpers import (
    require_repo_root,
)
from erk_shared.gateway.github.metadata.core import find_metadata_block


@click.command(name="get-plans-for-objective")
@click.argument("objective_number", type=int)
@click.pass_context
def get_plans_for_objective(ctx: click.Context, objective_number: int) -> None:
    """Fetch erk-plan issues linked to an objective.

    Lists all issues with the erk-plan label, then filters to those
    whose plan-header metadata contains objective_id matching the
    given objective number.
    """
    github = require_github_issues(ctx)
    repo_root = require_repo_root(ctx)

    try:
        all_plans = github.list_issues(
            repo_root=repo_root,
            labels=["erk-pr", "erk-plan"],
            state="all",
        )
    except RuntimeError as e:
        click.echo(
            json.dumps(
                {
                    "success": False,
                    "error": f"Failed to list erk-plan issues: {e}",
                }
            )
        )
        raise SystemExit(1) from e

    # Filter plans that reference this objective
    linked_plans = []
    for plan in all_plans:
        block = find_metadata_block(plan.body, "plan-header")
        if block is None:
            continue

        # Check both objective_id (new) and objective_issue (legacy)
        obj_id = block.data.get("objective_id") or block.data.get("objective_issue")
        if obj_id == objective_number:
            linked_plans.append(
                {
                    "number": plan.number,
                    "state": plan.state,
                    "title": plan.title,
                }
            )

    click.echo(
        json.dumps(
            {
                "success": True,
                "objective_number": objective_number,
                "plans": linked_plans,
            }
        )
    )

